// ── Region polygons (for PIP testing + rendering) ──
const MAP_OUTLINE_PATH = STEP_ORDER.map(
  (region) => MAP_REGIONS[region].path,
).join(" ");

function createGridPath(step: number) {
  let d = "";

  for (let y = 0; y <= MAP_VIEWBOX_HEIGHT; y += step) {
    d += `M0 ${y}L${MAP_VIEWBOX_WIDTH} ${y}`;
  }

  for (let x = 0; x <= MAP_VIEWBOX_WIDTH; x += step) {
    d += `M${x} 0L${x} ${MAP_VIEWBOX_HEIGHT}`;
  }

  return d;
}

const FINE_GRID = createGridPath(12);
const BOLD_GRID = createGridPath(48);

