function initSingaporeMap(section: HTMLElement) {
  const STEPS = STEP_ORDER.map((region) => ({
    region,
    label: MAP_REGIONS[region].label,
    quote: REGION_QUOTES[region],
  }));

  const SF_STEP_DUR = 7000;
  const SF_DWELL = 0.78;
  const SF_SCROLL_PER_STEP = 1000;
  const EASE = 0.06;

  const $svg = section.querySelector<SVGSVGElement>("#sg-map-svg");
  const $focusFill = section.querySelector<SVGPathElement>("#focus-fill");
  const $focusOutline = section.querySelector<SVGPathElement>("#focus-outline");
  const $glow = section.querySelector<SVGPathElement>("#glow");
  const $glowClipPath =
    section.querySelector<SVGPathElement>("#glow-clip-path");
  const $dotsDim = section.querySelector<SVGPathElement>("#dots-dim");
  const $dotsFade = section.querySelector<SVGPathElement>("#dots-fade");
  const $dotsMain = section.querySelector<SVGPathElement>("#dots-main");
  const $quoteText = section.querySelector<HTMLDivElement>("#quote-text");
  const $countryLabel =
    section.querySelector<HTMLDivElement>("#country-label");
  const $stepDotsWrap = section.querySelector<HTMLDivElement>("#step-dots");

  const regionEls = STEP_ORDER.reduce(
    (acc, region) => {
      acc[region] = section.querySelector<SVGPathElement>(`#region-${region}`);
      return acc;
    },
    {} as Record<RegionKey, SVGPathElement | null>,
  );

  if (
    !$svg ||
    !$focusFill ||
    !$focusOutline ||
    !$glow ||
    !$glowClipPath ||
    !$dotsDim ||
    !$dotsFade ||
    !$dotsMain ||
    !STEP_ORDER.every((region) => regionEls[region])
  ) {
    return () => {};
  }

  const svg = $svg;
  const focusFill = $focusFill;
  const focusOutline = $focusOutline;
  const glow = $glow;
  const glowClipPath = $glowClipPath;
  const dotsDim = $dotsDim;
  const dotsFade = $dotsFade;
  const dotsMain = $dotsMain;

  function makeLcg(seed: number) {
    let s = seed >>> 0;
    return function () {
      s = (s * 1664525 + 1013904223) >>> 0;
      return (s >>> 0) / 0xffffffff;
    };
  }

  function sampleInPath(
    pathEl: SVGGeometryElement,
    count: number,
    rng: () => number,
  ): Array<[number, number]> {
    const bb = pathEl.getBBox();
    const svgPoint = svg.createSVGPoint();
    const pts: Array<[number, number]> = [];
    const maxAttempts = count * 160;
    const inset = 3;
    const width = Math.max(bb.width - inset * 2, 1);
    const height = Math.max(bb.height - inset * 2, 1);

    for (let i = 0; pts.length < count && i < maxAttempts; i++) {
      svgPoint.x = bb.x + inset + rng() * width;
      svgPoint.y = bb.y + inset + rng() * height;
      if (pathEl.isPointInFill(svgPoint)) {
        pts.push([svgPoint.x, svgPoint.y]);
      }
    }

    return pts;
  }

  const rng = makeLcg(81000);
  const allDots: Array<[number, number, number]> = [];
  const dotPathByStep: Record<number, string> = {};

  STEPS.forEach((step, stepIdx) => {
    const regionPath = regionEls[step.region];
    if (!regionPath) return;

    const dots = sampleInPath(regionPath, MAP_REGIONS[step.region].dotCount, rng);
    dotPathByStep[stepIdx] = dots
      .map(([x, y]) => `M${x.toFixed(1)} ${y.toFixed(1)}h0.01`)
      .join("");

    dots.forEach(([x, y]) => {
      allDots.push([x, y, stepIdx]);
    });
  });

  const allDotsPath = allDots
    .map(([x, y]) => `M${x.toFixed(1)} ${y.toFixed(1)}h0.01`)
    .join("");

  dotsDim.setAttribute("d", allDotsPath);

  let stepDotEls: HTMLDivElement[] = [];

  function buildStepDots() {
    if (!$stepDotsWrap) return;
    $stepDotsWrap.innerHTML = "";
    stepDotEls = [];
    for (let i = 0; i < STEPS.length; i++) {
      const dot = document.createElement("div");
      dot.className = "step-dot";
      dot.dataset.idx = String(i);
      dot.addEventListener("click", function (e) {
        jumpToStep(
          parseInt((e.currentTarget as HTMLDivElement).dataset.idx!, 10),
        );
      });
      $stepDotsWrap.appendChild(dot);
      stepDotEls.push(dot);
    }
  }
  buildStepDots();

  function updateStepDotActive(idx: number) {
    for (let i = 0; i < stepDotEls.length; i++) {
      if (i === idx) stepDotEls[i].classList.add("active");
      else stepDotEls[i].classList.remove("active");
    }
  }

  let twTimer: ReturnType<typeof setTimeout> | null = null;
  let twRegion: RegionKey | null = null;
  let typewriterDone = true;

  function typewrite(text: string) {
    if (twTimer) {
      clearTimeout(twTimer);
      twTimer = null;
    }
    typewriterDone = false;
    if ($quoteText) {
      $quoteText.innerHTML =
        '<span class="sf-tw-cursor sf-blinking"></span>';
    }
    twTimer = setTimeout(function () {
      if ($quoteText) {
        $quoteText.innerHTML =
          '\u201c<span id="sf-tw-text"></span><span class="sf-tw-cursor sf-blinking"></span>';
      }
      const span = document.getElementById("sf-tw-text");
      if (!(span instanceof HTMLSpanElement)) return;
      const textSpan = span;
      let i = 0;
      function tick() {
        if (i >= text.length) {
          typewriterDone = true;
          return;
        }
        textSpan.textContent = (textSpan.textContent ?? "") + text[i++];
        twTimer = setTimeout(tick, 15);
      }
      tick();
    }, 1800);
  }

  const sfClamp = (x: number, a: number, b: number) =>
    Math.max(a, Math.min(b, x));

  let curMix = 1;
  let virtual = 0;
  let autoStart: number | null = null,
    autoOffset = 0;
  let lastRenderedStep = -1,
    currentStep = -1,
    prevStep = -1;
  let lastTypingDone = true,
    manualJump = false;
  let isSectionVisible = false;
  let isDocumentVisible = !document.hidden;
  let frameId: number | null = null;
  let destroyed = false;

  const syncLoopState = () => {
    const shouldRun = isSectionVisible && isDocumentVisible && !destroyed;
    if (!shouldRun) {
      if (frameId !== null) {
        cancelAnimationFrame(frameId);
        frameId = null;
      }
      return;
    }
    if (frameId === null) {
      frameId = requestAnimationFrame(loop);
    }
  };

  const visibilityObserver = new IntersectionObserver(
    (entries) => {
      const entry = entries[0];
      isSectionVisible = entry?.isIntersecting ?? false;
      syncLoopState();
    },
    { threshold: 0.1 },
  );
  visibilityObserver.observe(section);

  const onVisibilityChange = () => {
    isDocumentVisible = !document.hidden;
    syncLoopState();
  };
  document.addEventListener("visibilitychange", onVisibilityChange);

  function jumpToStep(i: number) {
    virtual = i * SF_SCROLL_PER_STEP;
    autoStart = null;
    typewriterDone = true;
    manualJump = true;
  }

  function render(stepIdx: number, prevStepIdx: number, focusAlpha: number) {
    if (stepIdx >= 0 && STEPS[stepIdx]) {
      const regionPath = MAP_REGIONS[STEPS[stepIdx].region].path;
      focusFill.setAttribute("d", regionPath);
      focusFill.setAttribute("fill-opacity", String(focusAlpha * 0.22));
      focusOutline.setAttribute("d", regionPath);
      focusOutline.setAttribute("stroke-opacity", String(focusAlpha));
      glow.setAttribute("d", regionPath);
      glow.setAttribute("stroke-opacity", String(focusAlpha * 0.24));
      glowClipPath.setAttribute("d", regionPath);
    } else {
      focusFill.setAttribute("d", "");
      focusFill.setAttribute("fill-opacity", "0");
      focusOutline.setAttribute("d", "");
      focusOutline.setAttribute("stroke-opacity", "0");
      glow.setAttribute("d", "");
      glow.setAttribute("stroke-opacity", "0");
      glowClipPath.setAttribute("d", "");
    }

    dotsMain.setAttribute("d", stepIdx >= 0 ? (dotPathByStep[stepIdx] || "") : "");
    dotsMain.setAttribute("stroke-opacity", String(0.8 * focusAlpha));
    dotsFade.setAttribute(
      "d",
      prevStepIdx >= 0 ? (dotPathByStep[prevStepIdx] || "") : "",
    );
    dotsFade.setAttribute("stroke-opacity", String(0.8 * (1 - focusAlpha)));
  }

  function loop(ts: number) {
    if (!isSectionVisible || !isDocumentVisible || destroyed) {
      frameId = null;
      return;
    }

    if (autoStart === null) {
      autoStart = ts;
      autoOffset = virtual;
    }

    const wasManualJump = manualJump;
    if (wasManualJump) manualJump = false;

    if (!typewriterDone) {
      autoStart = ts;
      autoOffset = virtual;
    } else if (!lastTypingDone && !wasManualJump) {
      const postDwellMs = 800;
      const skipFrac = Math.max(0, SF_DWELL - postDwellMs / SF_STEP_DUR);
      autoOffset =
        lastRenderedStep * SF_SCROLL_PER_STEP +
        skipFrac * SF_SCROLL_PER_STEP;
      autoStart = ts;
      virtual = autoOffset;
    }

    if (wasManualJump) lastTypingDone = true;
    else lastTypingDone = typewriterDone;

    virtual =
      autoOffset + ((ts - autoStart) / SF_STEP_DUR) * SF_SCROLL_PER_STEP;
    const totalVirtual = STEPS.length * SF_SCROLL_PER_STEP;
    virtual = ((virtual % totalVirtual) + totalVirtual) % totalVirtual;

    const stepFloat = virtual / SF_SCROLL_PER_STEP;
    const i = sfClamp(Math.floor(stepFloat), 0, STEPS.length - 1);

    if (i !== lastRenderedStep) {
      const prev = lastRenderedStep;
      lastRenderedStep = i;
      if (prev >= 0) curMix = 0;
      prevStep = prev;
      currentStep = i;
      updateStepDotActive(i);

      const step = STEPS[i];
      if ($countryLabel) {
        $countryLabel.innerHTML =
          '<span class="hl-yellow">' + step.label + "</span>";
      }

      if (twRegion !== step.region) {
        twRegion = step.region;
        typewrite(step.quote);
      }
    }

    curMix += (1 - curMix) * (EASE * 1.5);
    render(currentStep, prevStep, curMix);
    frameId = requestAnimationFrame(loop);
  }

  syncLoopState();

  return () => {
    destroyed = true;
    visibilityObserver.disconnect();
    document.removeEventListener("visibilitychange", onVisibilityChange);
    if (frameId !== null) {
      cancelAnimationFrame(frameId);
      frameId = null;
    }
    if (twTimer) {
      clearTimeout(twTimer);
      twTimer = null;
    }
  };
}
